26	/// @brief Define a valid kernel concept
27	template <typename QuantumKernel, typename... Args>
28	concept KernelCallValid =
29	    ValidArgumentsPassed<QuantumKernel, Args...> &&
30	    HasVoidReturnType<std::invoke_result_t<QuantumKernel, Args...>>;
31	
32	namespace detail {
33	
34	/// @brief Execute the given kernel functor and extract the
35	/// state representation.
36	template <typename KernelFunctor>
37	state extractState(KernelFunctor &&kernel) {
38	  // Get the platform.
39	  auto &platform = cudaq::get_platform();
40	
41	  // This can only be done in simulation
42	  if (!platform.is_simulator())
43	    throw std::runtime_error("Cannot use get_state on a physical QPU.");
44	  // Create an execution context, indicate this is for
45	  // extracting the state representation
46	  ExecutionContext context("extract-state");
47	
48	  platform.with_execution_context(context, std::forward<KernelFunctor>(kernel));
49	
50	  // Return the state data. Since the ExecutionContext
51	  // is done being used, we'll move the simulation state
52	  // pointer to the state type. The state will retain
53	  // value semantics, due to its tracking of this simulation
54	  // data as a shared_ptr.
55	  return state(context.simulationState.release());
56	}
57	
58	template <typename KernelFunctor>
59	auto runGetStateAsync(KernelFunctor &&wrappedKernel,
60	                      cudaq::quantum_platform &platform, std::size_t qpu_id) {
61	  // This can only be done in simulation
62	  if (!platform.is_simulator())
63	    throw std::runtime_error("Cannot use get_state_async on a physical QPU.");
64	
65	  if (qpu_id >= platform.num_qpus())
66	    throw std::invalid_argument("Provided qpu_id " + std::to_string(qpu_id) +
67	                                " is invalid (must be < " +
68	                                std::to_string(platform.num_qpus()) +
69	                                " i.e. platform.num_qpus())");
70	
71	  std::promise<state> promise;
72	  auto f = promise.get_future();
73	  // Wrapped it as a generic (returning void) function
74	  QuantumTask wrapped = detail::make_copyable_function(
75	      [p = std::move(promise), qpu_id, &platform,
76	       func = std::forward<KernelFunctor>(wrappedKernel)]() mutable {
77	        ExecutionContext context("extract-state");
78	        // Indicate that this is an async exec
79	        context.asyncExec = true;
80	        context.qpuId = qpu_id;
81	        // Set the platform and the qpu id.
82	        platform.with_execution_context(context,
83	                                        std::forward<KernelFunctor>(func));
84	        // Extract state data
85	        p.set_value(state(context.simulationState.release()));
86	      });
87	
88	  platform.enqueueAsyncTask(qpu_id, wrapped);
89	  return f;
90	}
91	
92	} // namespace detail
93	
94	/// @brief Return the state representation generated by the kernel at the given
95	/// runtime arguments.
96	template <typename QuantumKernel, typename... Args>
97	auto get_state(QuantumKernel &&kernel, Args &&...args) {
98	#if defined(CUDAQ_QUANTUM_DEVICE) && !defined(CUDAQ_LIBRARY_MODE)
99	  // Store kernel name and arguments for quantum states.
100	  const auto kernelName =
101	      detail::getKernelName(std::forward<QuantumKernel>(kernel));
102	  return state(new QPUState(kernelName, cudaq::get_quake_by_name(kernelName),
103	                            std::forward<Args>(args)...));
104	
105	#elif defined(CUDAQ_QUANTUM_DEVICE)
106	  // Kernel builder is MLIR-based kernel.
107	  if constexpr (has_name<QuantumKernel>::value) {
108	    const auto kernelName =
109	        detail::getKernelName(std::forward<QuantumKernel>(kernel));
110	    return state(new QPUState(kernelName, cudaq::get_quake_by_name(kernelName),
111	                              std::forward<Args>(args)...));
112	  }
113	  throw std::runtime_error(
114	      "could not create state in library mode for quantum devices");
115	#else
116	  return detail::extractState(
117	      [&]() mutable { kernel(std::forward<Args>(args)...); });
118	#endif
119	}
120	
121	/// @brief Return type for asynchronous `get_state`.
122	using async_state_result = std::future<state>;
123	
124	/// \brief Return the state representation generated by the kernel at the given
125	/// runtime arguments asynchronously.
126	///
127	/// @param `qpu_id` the id of the QPU to run asynchronously on
128	/// @param kernel the kernel expression, must contain final measurements
129	/// @param `args` the variadic concrete arguments for evaluation of the kernel.
130	/// \returns state future, A std::future containing the resultant state vector
131	///
132	template <typename QuantumKernel, typename... Args>
133	  requires KernelCallValid<QuantumKernel, Args...>
134	async_state_result get_state_async(std::size_t qpu_id, QuantumKernel &&kernel,
135	                                   Args &&...args) {
136	  auto &platform = cudaq::get_platform();
137	  return detail::runGetStateAsync(
138	      [&kernel, ... args = std::forward<Args>(args)]() mutable {
139	        kernel(std::forward<Args>(args)...);
140	      },
141	      platform, qpu_id);
142	}
143	
144	/// \brief Return the state representation generated by the kernel at the given
145	/// runtime arguments asynchronously on the default QPU (id = 0).
146	///
147	/// @param kernel the kernel expression, must contain final measurements
148	/// @param `args` the variadic concrete arguments for evaluation of the kernel.
149	/// \returns state future, A std::future containing the resultant state vector
150	///
151	template <typename QuantumKernel, typename... Args>
152	  requires KernelCallValid<QuantumKernel, Args...>
153	async_state_result get_state_async(QuantumKernel &&kernel, Args &&...args) {
154	  return get_state_async(0, std::forward<QuantumKernel>(kernel),
155	                         std::forward<Args>(args)...);
156	}
