8	
9	#pragma once
10	
11	#include "common/Trace.h"
12	#include "nvqir/Gates.h"
13	#include "cudaq/algorithms/draw.h"
14	#include "cudaq/operators/matrix.h"
15	#include <iostream>
16	
17	namespace cudaq::contrib {
18	
19	/// @brief Build a controlled-gate unitary: identity in all control blocks
20	/// except the “all controls = 1” block, which is replaced by the original gate.
21	/// @param gate The base unitary matrix of the target gate.
22	/// @param num_controls The number of control qubits.
23	/// @returns A complex_matrix representing the controlled version of the gate.
24	inline complex_matrix make_controlled_unitary(const complex_matrix &gate,
25	                                              std::size_t num_controls) {
26	  auto gdim = gate.rows();
27	  auto ctrl_dim = 1ULL << num_controls;
28	  auto new_dim = ctrl_dim * gdim;
29	  // Start with identity of full size
30	  complex_matrix M = complex_matrix::identity(new_dim);
31	  // Offset of the “all controls = 1” block
32	  auto offset = (ctrl_dim - 1) * gdim;
33	  // Overwrite bottom-right block with gate
34	  for (std::size_t i = 0; i < gdim; ++i)
35	    for (std::size_t j = 0; j < gdim; ++j)
36	      M(offset + i, offset + j) = gate(i, j);
37	  return M;
38	}
39	
40	/// @brief Apply an m-qubit gate in place to an n-qubit unitary.
41	/// @param U The 2^n x 2^n unitary, modified in place.
42	/// @param gate The 2^m x 2^m gate matrix.
43	/// @param num_qubits The total number of qubits in the full system.
44	/// @param qubit_indices A vector of size m giving the qubit indices the gate
45	/// acts on in the full system.
46	inline void apply_gate_in_place(complex_matrix &U, const complex_matrix &gate,
47	                                std::size_t num_qubits,
48	                                const std::vector<std::size_t> &qubit_indices) {
49	  using value_type = std::complex<double>;
50	  const std::size_t m = qubit_indices.size();
51	  const std::size_t gdim = 1ULL << m;
52	  const std::size_t dim = 1ULL << num_qubits;
53	
54	  // Bit position of each affected qubit in the system index.
55	  std::vector<std::size_t> bp(m);
56	  std::size_t affected_mask = 0;
57	  for (std::size_t k = 0; k < m; ++k) {
58	    bp[k] = num_qubits - 1 - qubit_indices[k];
59	    affected_mask |= (1ULL << bp[k]);
60	  }
61	
62	  // Local row-major copy of the gate so the inner loop is a tight indexed
63	  // multiply-add without going through complex_matrix accessors.
64	  std::vector<value_type> g(gdim * gdim);
65	  for (std::size_t a = 0; a < gdim; ++a)
66	    for (std::size_t b = 0; b < gdim; ++b)
67	      g[a * gdim + b] = gate(a, b);
68	
69	  // scatter[a] deposits the m bits of a into the bp[] positions. Bit (m-1-k)
70	  // of a is the k-th qubit's value (MSB-first within the gate, matching the
71	  // gate's row/column encoding).
72	  std::vector<std::size_t> scatter(gdim, 0);
73	  for (std::size_t a = 0; a < gdim; ++a) {
74	    std::size_t s = 0;
75	    for (std::size_t k = 0; k < m; ++k)
76	      if ((a >> (m - 1 - k)) & 1ULL)
77	        s |= (1ULL << bp[k]);
78	    scatter[a] = s;
79	  }
80	
81	  value_type *udata = U.get_data(complex_matrix::order::row_major);
82	
83	  std::vector<value_type> col_old(gdim);
84	  std::vector<value_type> col_new(gdim);
85	  std::vector<std::size_t> rows(gdim);
86	
87	  // Iterate over all "base" row indices that have zero in every affected bit.
88	  // For each base, the 2^m affected rows are base | scatter[a].
89	  for (std::size_t base = 0; base < dim; ++base) {
90	    if (base & affected_mask)
91	      continue;
92	    for (std::size_t a = 0; a < gdim; ++a)
93	      rows[a] = base | scatter[a];
94	
95	    for (std::size_t j = 0; j < dim; ++j) {
96	      for (std::size_t b = 0; b < gdim; ++b)
97	        col_old[b] = udata[rows[b] * dim + j];
98	      for (std::size_t a = 0; a < gdim; ++a) {
99	        value_type acc(0.0, 0.0);
100	        for (std::size_t b = 0; b < gdim; ++b)
101	          acc += g[a * gdim + b] * col_old[b];
102	        col_new[a] = acc;
103	      }
104	      for (std::size_t a = 0; a < gdim; ++a)
105	        udata[rows[a] * dim + j] = col_new[a];
106	    }
107	  }
108	}
109	
110	/// @brief Construct the full system unitary from a Trace of quantum
111	/// instructions.
112	/// @param trace The Trace object recording the sequence of quantum operations.
113	/// @returns A complex_matrix representing the overall unitary of the traced
114	/// kernel.
115	inline complex_matrix unitary_from_trace(const Trace &trace) {
116	  auto num_qubits = trace.getNumQudits();
117	  std::size_t dim = 1ULL << num_qubits;
118	  complex_matrix U = complex_matrix::identity(dim);
119	
120	  for (const auto &inst : trace) {
121	    auto gate_name = nvqir::getGateNameFromString(inst.name);
122	    auto gate_vec = nvqir::getGateByName<double>(gate_name, inst.params);
123	    std::size_t gate_dim = static_cast<std::size_t>(std::sqrt(gate_vec.size()));
124	    complex_matrix gate(gate_vec, {gate_dim, gate_dim});
125	
126	    // If there are control qubits, build the controlled-unitary
127	    if (!inst.controls.empty())
128	      gate = make_controlled_unitary(gate, inst.controls.size());
129	
130	    // Get vector of all qubit indices that this gate operates on.
131	    // The control qubits are expected to be at the start of the vector.
132	    std::vector<std::size_t> inst_qubits;
133	    inst_qubits.reserve(inst.controls.size() + inst.targets.size());
134	    for (const auto &control : inst.controls)
135	      inst_qubits.push_back(control.id);
136	    for (const auto &target : inst.targets)
137	      inst_qubits.push_back(target.id);
138	
139	    apply_gate_in_place(U, gate, num_qubits, inst_qubits);
140	  }
141	  return U;
142	}
143	
144	/// @brief Execute a quantum kernel and return its unitary as a complex_matrix.
145	/// @tparam QuantumKernel The functor type of the quantum kernel.
146	/// @param kernel The quantum kernel to execute.
147	/// @param args Arguments to pass to the kernel.
148	/// @returns The full system unitary as a complex_matrix.
149	template <typename QuantumKernel, typename... Args>
150	complex_matrix get_unitary_cmat(QuantumKernel &&kernel, Args &&...args) {
151	  auto trace = traceFromKernel(kernel, std::forward<Args>(args)...);
152	  return unitary_from_trace(trace);
153	}
154	
155	} // namespace cudaq::contrib
