26	/// @brief Encapsulates a list of tensors (data pointer and dimensions).
27	// Note: tensor data is expected in column-major.
28	using TensorStateData =
29	    std::vector<std::pair<const void *, std::vector<std::size_t>>>;
30	/// @brief state_data is a variant type
31	/// encoding different forms of user state vector data
32	/// we support.
33	using state_data = std::variant<std::vector<std::complex<double>>,
34	                                std::vector<std::complex<float>>,
35	                                std::pair<std::complex<double> *, std::size_t>,
36	                                std::pair<std::complex<float> *, std::size_t>,
37	                                complex_matrix, TensorStateData>;
38	
39	/// @brief The `SimulationState` interface provides and extension point
40	/// for concrete circuit simulation sub-types to describe their
41	/// underlying quantum state data in an efficient manner. The `SimulationState`
42	/// provides a handle on the data for clients, with data remaining on GPU
43	/// device or CPU memory. The primary goal of this type and its sub-types
44	/// is to minimize data transfers for the state.
45	class SimulationState {
46	protected:
47	  /// @brief Utility method to inspect the state_data variant
48	  /// and extract the data pointer and size.
49	  template <typename T, typename ScalarType = double>
50	  auto getSizeAndPtrFromVec(const state_data &data) {
51	    if constexpr (!std::is_same_v<T, ScalarType>)
52	      throw std::runtime_error("[sim-state] invalid data precision.");
53	
54	    auto &vec = std::get<std::vector<std::complex<T>>>(data);
55	    return std::make_tuple(
56	        vec.size(),
57	        reinterpret_cast<void *>(const_cast<std::complex<T> *>(vec.data())));
58	  };
59	
60	  /// @brief Utility method to inspect the state_data variant
61	  /// and extract the data pointer and size.
62	  template <typename T, typename ScalarType = double>
63	  auto getSizeAndPtrFromPair(const state_data &data) {
64	    if constexpr (!std::is_same_v<T, ScalarType>)
65	      throw std::runtime_error("[sim-state] invalid data precision.");
66	
67	    auto &pair = std::get<std::pair<std::complex<T> *, std::size_t>>(data);
68	    return std::make_tuple(pair.second, reinterpret_cast<void *>(pair.first));
69	  };
70	
71	  /// @brief Utility method to inspect the state_data variant
72	  /// and extract the data pointer and size.
73	  template <typename ScalarType = double>
74	  auto getSizeAndPtr(const state_data &data) {
75	    std::tuple<std::size_t, void *> sizeAndPtr;
76	    if (std::holds_alternative<std::vector<std::complex<double>>>(data))
77	      sizeAndPtr = getSizeAndPtrFromVec<double, ScalarType>(data);
78	    else if (std::holds_alternative<std::vector<std::complex<float>>>(data))
79	      sizeAndPtr = getSizeAndPtrFromVec<float, ScalarType>(data);
80	    else if (std::holds_alternative<
81	                 std::pair<std::complex<double> *, std::size_t>>(data))
82	      sizeAndPtr = getSizeAndPtrFromPair<double, ScalarType>(data);
83	    else if (std::holds_alternative<
84	                 std::pair<std::complex<float> *, std::size_t>>(data))
85	      sizeAndPtr = getSizeAndPtrFromPair<float, ScalarType>(data);
86	    else
87	      throw std::runtime_error("unsupported data type for state vector.");
88	
89	    auto &[size, ptr] = sizeAndPtr;
90	    if (!ptr || size == 0)
91	      throw std::runtime_error(
92	          "[getSizeAndPtr] invalid null pointer or zero size");
93	
94	    return sizeAndPtr;
95	  }
96	
97	  /// @brief Subclass-specific creator method for
98	  /// new SimulationState instances. Create from the size
99	  /// and data pointer, which may be on GPU device.
100	  virtual std::unique_ptr<SimulationState>
101	  createFromSizeAndPtr(std::size_t, void *, std::size_t dataType) = 0;
102	
103	public:
104	  /// @brief Runtime-known precision for the simulation data
105	  enum class precision { fp32, fp64 };
106	
107	  /// @brief Simulation states are made up of a
108	  /// vector of Tensors. Each tensor tracks its data pointer
109	  /// and the tensor extents.
110	  struct Tensor {
111	    void *data = nullptr;
112	    std::vector<std::size_t> extents;
113	    precision fp_precision;
114	    std::size_t get_rank() const { return extents.size(); }
115	    std::size_t get_num_elements() const {
116	      std::size_t num = 1;
117	      for (auto &el : extents)
118	        num *= el;
119	      return num;
120	    }
121	    std::size_t element_size() const {
122	      return fp_precision == precision::fp32 ? sizeof(std::complex<float>)
123	                                             : sizeof(std::complex<double>);
124	    }
125	  };
126	
127	  /// @brief Create a new subclass specific SimulationState
128	  /// from the user provided data set.
129	  virtual std::unique_ptr<cudaq::SimulationState>
130	  createFromData(const state_data &data) {
131	    if (std::holds_alternative<TensorStateData>(data)) {
132	      if (isArrayLike())
133	        throw std::runtime_error(
134	            "Cannot initialize state vector/density matrix state by matrix "
135	            "product state tensors. Please use tensor network simulator "
136	            "backends.");
137	      auto &dataCasted = std::get<TensorStateData>(data);
138	      return createFromSizeAndPtr(
139	          dataCasted.size(),
140	          const_cast<TensorStateData::value_type *>(dataCasted.data()),
141	          data.index());
142	    }
143	    // Flat array state data
144	    // Check the precision first. Get the size and
145	    // data pointer from the input data.
146	
147	    if (getPrecision() == precision::fp32) {
148	      auto [size, ptr] = getSizeAndPtr<float>(data);
149	      return createFromSizeAndPtr(size, ptr, data.index());
150	    }
151	
152	    auto [size, ptr] = getSizeAndPtr(data);
153	    return createFromSizeAndPtr(size, ptr, data.index());
154	  }
155	
156	  /// @brief True if the state has amplitudes or density matrix
157	  // is available or can be computed.
158	  virtual bool hasData() const { return true; }
159	
160	  /// @brief Helper to retrieve (kernel name, kernel code, and `args` pointers)
161	  virtual std::optional<
162	      std::tuple<std::string, std::string, std::vector<void *>>>
